<?php require_once __DIR__.'/../../config/database.php'; require_once __DIR__.'/../../includes/functions.php'; require_admin(); if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); if(isset($_POST['delete']))$pdo->prepare('DELETE FROM users WHERE id=?')->execute([$_POST['id']]); else $pdo->prepare('INSERT INTO users(role_id,name,email,password) VALUES(?,?,?,?)')->execute([$_POST['role_id'],$_POST['name'],$_POST['email'],password_hash($_POST['password'],PASSWORD_DEFAULT)]); } $roles=$pdo->query('SELECT * FROM roles')->fetchAll(); $rows=$pdo->query('SELECT u.*,r.name role FROM users u JOIN roles r ON r.id=u.role_id')->fetchAll(); require_once __DIR__.'/../../includes/header.php'; ?><div class="container-fluid px-3 px-lg-4"><div class="row g-3"><?php include __DIR__.'/../../includes/admin_sidebar.php'; ?><section class="col-lg-9 col-xl-10"><h2 class="section-title mb-3">CRUD Pengguna</h2><form class="card p-3 mb-3" method="post"><?=csrf_field()?><div class="row g-2"><div class="col"><input name="name" class="form-control" placeholder="Nama"></div><div class="col"><input name="email" type="email" class="form-control" placeholder="Email"></div><div class="col"><input name="password" type="password" class="form-control" placeholder="Password"></div><div class="col"><select name="role_id" class="form-select"><?php foreach($roles as $r): ?><option value="<?=$r['id']?>"><?=$r['name']?></option><?php endforeach; ?></select></div><div class="col"><button class="btn btn-primary">Simpan</button></div></div></form><div class="table-wrap"><table class="table table-hover"><tr><th>Nama</th><th>Email</th><th>Role</th><th>Aksi</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['name'])?></td><td><?=e($r['email'])?></td><td><?=e($r['role'])?></td><td><form method="post"><?=csrf_field()?><input type="hidden" name="id" value="<?=$r['id']?>"><button name="delete" class="btn btn-sm btn-danger">Hapus</button></form></td></tr><?php endforeach; ?></table></div></section></div></div><?php require_once __DIR__.'/../../includes/footer.php'; ?>
